  malphite: { diff: "EVEN", tone: "#e8b84b", tldr: "E-taunt his poke \u2014 W-block, out-trade him.", breakdown: "E-taunt him, W-block his Q poke autos, and out-trade; play for R roams.", dos: ["E-taunt into Q", "W-block his autos", "Play for R roams"], donts: ["Auto into his W", "Eat his R knockup", "Fall behind in scaling"], key: { slot: "R", name: "Unstoppable Force", cd: "130s", note: "His engage. E-taunt when down.", winT: "ULT DOWN", winS: "E-Q + R him." }, hold: "Hold E to taunt him \u2014 trade and play for R; W-block his autos.", tip: "E-taunt him and W-block his poke autos \u2014 out-trade and impact the map with R.", win: "Taunt him and play for R." },
