  poppy: { diff: "EVEN", tone: "#e8b84b", tldr: "Dodge her E \u2014 E-taunt her, out-trade her.", breakdown: "Dodge her E, E-taunt her, W-block her combo, and out-trade her low-threat kit.", dos: ["Dodge her E wall-stun", "E-taunt into Q", "W-block her autos"], donts: ["Get E-pinned on a wall", "Get R-knocked mid-combo", "Fall behind in scaling"], key: { slot: "E", name: "Heroic Charge", cd: "14s", note: "Wall-pin stun. Dodge it.", winT: "CHARGE DOWN", winS: "E-Q + R her." }, hold: "Hold E to taunt her \u2014 trade and play for R; W-block her autos.", tip: "Dodge her E, E-taunt her, and W-block her combo \u2014 out-trade her kit.", win: "Taunt her and play for R." },
  shen: { diff: "MIRROR", tone: "#e8b84b", tldr: "Spirit-blade mirror \u2014 whoever uses W + E better, and roams with R, wins.", breakdown: "Pure Shen mirror: it\u2019s a W-block and E-taunt mind-game \u2014 whoever impacts the map with R harder wins.", dos: ["Win the W-block timing", "E-taunt into Q first", "Out-roam with R"], donts: ["Waste W early", "Get taunted first", "Miss R timings"], key: { slot: "R", name: "Stand United", cd: "200s", note: "Whoever impacts the map with R harder wins.", winT: "R READY", winS: "E-Q + R him." }, hold: "Hold W to block his autos and E to taunt-trade \u2014 but the lane is decided by who roams with R better.", tip: "It\u2019s a W-block and E-taunt mirror \u2014 win the trade, but out-impact him with global R.", win: "Win the trade and out-roam with R." },
  sion: { diff: "EVEN", tone: "#e8b84b", tldr: "Dodge his Q \u2014 E-taunt, out-trade his early.", breakdown: "Dodge his charged Q, E-taunt him, W-block his combo, and out-trade his early.", dos: ["Dodge his charged Q", "E-taunt into Q", "W-block his autos"], donts: ["Eat a full Q stun", "Fight into his W shield", "Fall behind in scaling"], key: { slot: "Q", name: "Decimating Smash (Stun)", cd: "8s", note: "Charged = knockup. Dodge it.", winT: "Q DOWN", winS: "E-Q + R him." }, hold: "Hold E to taunt his immobile body \u2014 trade and play for R; W-block his autos.", tip: "Dodge his charged Q, E-taunt him, and W-block his combo \u2014 out-trade his early.", win: "Taunt him and play for R." },
  tahmkench: { diff: "EVEN", tone: "#e8b84b", tldr: "Dodge his tongue \u2014 E-taunt, out-trade him.", breakdown: "Dodge his Q tongue, E-taunt him, W-block his combo, and out-trade his tank kit.", dos: ["Dodge his Q tongue", "E-taunt into Q", "W-block his autos"], donts: ["Get Q-stunned", "Fight into his W reactivate", "Eat free passive stacks"], key: { slot: "W", name: "Abyssal Dive", cd: "12s", note: "His escape + shield. Trade when down.", winT: "W DOWN", winS: "E-Q + R him." }, hold: "Hold E to taunt him \u2014 trade and play for R; W-block his autos.", tip: "Dodge his Q tongue, E-taunt him, and W-block his combo \u2014 out-trade his tank kit.", win: "Taunt him and play for R." },
  zac: { diff: "EVEN", tone: "#e8b84b", tldr: "Step on blobs \u2014 E-taunt, anti-heal him.", breakdown: "Step on his blobs, E-taunt him, W-block his autos, and anti-heal his sustain.", dos: ["Step on his blobs", "E-taunt into Q", "Anti-heal his sustain"], donts: ["Let him eat blobs", "Get E-knocked-up", "Fall behind in scaling"], key: { slot: "E", name: "Elastic Slingshot", cd: "16s", note: "His engage. E-taunt after it.", winT: "SLINGSHOT DOWN", winS: "E-Q + R him." }, hold: "Hold E to taunt him as he slingshots in \u2014 cancel his engage and trade.", tip: "Deny his blobs, E-taunt him, W-block his autos, and anti-heal \u2014 out-trade his kit.", win: "Taunt him and play for R." },
