  akali: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Build MR \u2014 E-taunt her off shroud, W-block.", breakdown: "Build MR, E-taunt her off her shroud, W-block her autos, and play for R.", dos: ["Build MR", "E-taunt her off shroud", "W-block her autos"], donts: ["Fight her 6 with no MR", "Get Q-poked down", "Chase her into shroud"], key: { slot: "W", name: "Twilight Shroud", cd: "18s", note: "Untargetable inside. E-taunt before it.", winT: "SHROUD DOWN", winS: "E-Q + R her." }, hold: "Hold E to taunt her before she shrouds \u2014 cancel her burst; build MR and W-block her autos.", tip: "Build MR, E-taunt her off her shroud, and W-block her autos \u2014 play for R roams.", win: "Build MR and taunt her off shroud." },
