  gangplank: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Pop barrels \u2014 E-taunt him, roam with R.", breakdown: "Pop his barrels, E-taunt him, W-block his autos, and play for global R.", dos: ["Pop his barrels", "E-taunt into Q", "Play for R roams"], donts: ["Eat a full barrel chain", "Let him free-scale", "Fall behind in farm"], key: { slot: "E", name: "Powder Kegs", cd: "18s", note: "Pop barrels to deny poke + gold.", winT: "BARRELS CLEARED", winS: "E-Q + R him." }, hold: "Hold E to taunt him when he steps to a barrel \u2014 cancel his combo before it chains.", tip: "Pop his barrels, E-taunt him, and W-block his autos \u2014 impact the map with R.", win: "Deny barrels and play for R." },
  gnar: { diff: "TRICKY", tone: "#ff8b3d", tldr: "His %HP hurts \u2014 E-taunt mini, respect Mega CC.", breakdown: "Gnar\u2019s %HP boomerang chunks you. E-taunt mini-Gnar, W-block, build mixed, and dodge Mega.", dos: ["Build mixed resists", "E-taunt mini-Gnar", "Dodge Mega\u2019s all-in"], donts: ["Get kited in mini form", "Fight Mega\u2019s all-in", "Stack pure HP vs %damage"], key: { slot: "R", name: "GNAR! (Mega Stun)", cd: "90s", note: "His Mega all-in. Dodge it.", winT: "MINI FORM", winS: "E-Q + R him." }, hold: "Hold E to taunt mini-Gnar \u2014 it stops his kite; W-block his autos, dodge Mega.", tip: "His %-HP boomerang chunks you \u2014 E-taunt mini-Gnar, build mixed, and dodge Mega.", win: "Taunt mini and dodge Mega." },
  heimerdinger: { diff: "TRICKY", tone: "#ff8b3d", tldr: "His turrets out-poke you \u2014 build MR, E-taunt him off nest.", breakdown: "Heimer\u2019s turrets out-poke you. Build MR, E-taunt him out of his nest, and W-block to dive.", dos: ["Build MR", "E-taunt him off his nest", "W-block to dive"], donts: ["Dive a full nest raw", "Eat his E stun", "Poke-war into turrets"], key: { slot: "E", name: "CH-2 Grenade (Stun)", cd: "11s", note: "His self-peel stun. Dodge it.", winT: "GRENADE DOWN", winS: "E-Q + R him." }, hold: "Hold E to taunt him out of his nest \u2014 carry him off his turrets; W-block the beams to dive.", tip: "Build MR, E-taunt him off his nest, and W-block the turret beams to dive him.", win: "Build MR and taunt him off his nest." },
  jayce: { diff: "TRICKY", tone: "#ff8b3d", tldr: "He pokes you out \u2014 E-taunt him, roam with R.", breakdown: "Jayce out-pokes you. Build a little armor, E-taunt him to close, and play for global R.", dos: ["Build a little armor", "E-taunt to close", "Play for R roams"], donts: ["Walk into his Q-gate", "Get E-knocked", "Let the poke war drag"], key: { slot: "Q", name: "Shock Blast", cd: "6s", note: "His main poke. Dodge it.", winT: "SHOCK BLAST DOWN", winS: "E-Q + R him." }, hold: "Hold E to taunt him when he poke-steps \u2014 dash on and cancel his combo.", tip: "Build a little armor, E-taunt him to close, and play for R \u2014 your global wins where lane can\u2019t.", win: "Taunt his poke and play for R." },
  kayle: { diff: "EVEN", tone: "#e8b84b", tldr: "Both scale \u2014 E-taunt her early, deny her CS.", breakdown: "Both scale. E-taunt her off CS early, W-block her autos, and play for global R.", dos: ["E-taunt her off CS", "Deny her CS + XP", "Play for R roams"], donts: ["Let her free-farm", "Fall behind in scaling", "Fight late from behind"], key: { slot: "R", name: "Divine Judgment (Invuln)", cd: "100s", note: "Her get-out at 6. Bait it.", winT: "JUDGMENT DOWN", winS: "E-Q + R her." }, hold: "Hold E to taunt her off a CS \u2014 deny her farm; play for R while she\u2019s weak.", tip: "It\u2019s a scaling race \u2014 E-taunt her off CS early and impact the map with R before she scales.", win: "Deny her early and play for R." },
