  quinn: { diff: "TRICKY", tone: "#ff8b3d", tldr: "She pokes + kites \u2014 E-taunt her kite, roam with R.", breakdown: "Quinn out-pokes you. E-taunt her (stops her kite), W-block her autos, and play for R.", dos: ["E-taunt her kite", "W-block her autos", "Play for R roams"], donts: ["Fight into her blind", "Poke-war from range", "Let her kite you out"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. E-taunt around it.", winT: "VAULT DOWN", winS: "E-Q + R her." }, hold: "Hold E to taunt her \u2014 the dash + taunt stop her kite; W-block her autos.", tip: "E-taunt her to stop her kite, W-block her autos, and play for R \u2014 your global beats her lane.", win: "Taunt her kite and play for R." },
  rumble: { diff: "TRICKY", tone: "#ff8b3d", tldr: "His %HP DoT hurts \u2014 build MR, E-taunt him.", breakdown: "Rumble\u2019s flamespitter does %HP. Build MR, E-taunt him out of it, and dodge his R line.", dos: ["Build MR", "E-taunt him out of flame", "Dodge his R line"], donts: ["Stand in his flamespitter", "Stack pure HP vs %damage", "Sit in his R line"], key: { slot: "W", name: "Scrap Shield", cd: "6s", note: "Bait it, then commit.", winT: "SHIELD DOWN", winS: "E-Q + R him." }, hold: "Hold E to taunt him out of his flamespitter range \u2014 build MR since his DoT is magic.", tip: "His %-HP flamespitter chunks you \u2014 build MR, E-taunt him out of it, and dodge his Equalizer.", win: "Build MR and taunt him out." },
