  swain: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 E-taunt him, dodge his E root.", breakdown: "Build MR, E-taunt him, dodge his E root, and play for global R.", dos: ["Build MR", "E-taunt into Q", "Dodge his E root"], donts: ["Fight into his R drain", "Get E-rooted", "Fall behind in scaling"], key: { slot: "R", name: "Demonic Ascension", cd: "100s", note: "His drain. Trade when it\u2019s down.", winT: "ASCENSION DOWN", winS: "E-Q + R him." }, hold: "Hold E to taunt him \u2014 trade and play for R; build MR and dodge his E root.", tip: "Build MR, E-taunt him, and dodge his E root \u2014 impact the map with R.", win: "Build MR and taunt him." },
  teemo: { diff: "HARD", tone: "#ff5d6c", tldr: "His blind + %HP + kite \u2014 build MR, E-taunt his kite.", breakdown: "Teemo blinds your autos, shrooms do %HP, and he kites. Build MR, E-taunt him (ignores blind), and roam with R.", dos: ["Build MR + dodge shrooms", "E-taunt him (ignores blind)", "Play for R roams"], donts: ["Auto into his blind", "Chase through shrooms", "Stack pure HP vs %damage"], key: { slot: "Q", name: "Blinding Dart", cd: "7s", note: "Blinds your autos. E-taunt instead.", winT: "BLIND DOWN", winS: "E-Q + R him." }, hold: "Hold E to taunt him \u2014 the dash + taunt ignore his blind and stop his kite.", tip: "His blind only stops autos \u2014 E-taunt him (it ignores blind, stops his kite), build MR, and play for R.", win: "Taunt his kite and play for R." },
