  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — taunt him on the Heroic Swing cooldown and win the map with R.","breakdown":"Akshan plays around Heroic Swing. E-taunt his Heroic Swing gap, W-block the answer, Q-pull the spirit blade through him — and never forget the lane is second to your R map game. Doran’s Shield blunts the poke war.","dos":["E-taunt when Heroic Swing is down","W-block his big auto window","Track your R for cross-map saves"],"donts":["Push when your R could save a lane","Taunt into the wave","Waste W on poke"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"E-taunt + empowered Qs."},"win":"Taunt him on the Heroic Swing cooldown and win the map with R."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then taunt him on the Miasma cooldown and win the map with R.","breakdown":"Cassiopeia plays around Miasma. E-taunt his Miasma gap, W-block the answer, Q-pull the spirit blade through him — and never forget the lane is second to your R map game. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["E-taunt when Miasma is down","W-block his big auto window","Track your R for cross-map saves"],"donts":["Push when your R could save a lane","Taunt into the wave","Waste W on poke"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"E-taunt + empowered Qs."},"win":"Taunt him on the Miasma cooldown and win the map with R."},
  galio: {"diff":"EVEN","tone":"#e8b84b","tldr":"Bait his key tool — taunt him on the Justice Punch cooldown and win the map with R.","breakdown":"Galio plays around Justice Punch. E-taunt his Justice Punch gap, W-block the answer, Q-pull the spirit blade through him — and never forget the lane is second to your R map game. Take Mercs / MR shard — his damage is magic.","dos":["E-taunt when Justice Punch is down","W-block his big auto window","Track your R for cross-map saves"],"donts":["Push when your R could save a lane","Taunt into the wave","Waste W on poke"],"key":{"slot":"E","name":"Justice Punch","cd":"13s","note":"His dash + knockup engage. Punish him when it's down.","winT":"JUSTICE PUNCH DOWN","winS":"E-taunt + empowered Qs."},"win":"Taunt him on the Justice Punch cooldown and win the map with R."},
